// Exploring all five common primitive types

// string — text in quotes or backticks
const productName  = "CodeGuru Pro Plan";
const city         = 'Mumbai';
const templateDemo = `Product: ${productName}`; // template literal

// number — integers and decimals use the same type
const price        = 2999;
const taxRate      = 0.18;
const discounted   = price * (1 - taxRate);

// boolean — only two possible values
const isAvailable  = true;
const isExpired    = false;

// undefined — declared but not assigned
let promoCode;
console.log("promoCode:", promoCode);   // undefined

// null — explicitly empty
const selectedItem = null;

// Log everything with their types
console.log(productName,  "|", typeof productName);
console.log(price,         "|", typeof price);
console.log(isAvailable,  "|", typeof isAvailable);
console.log(promoCode,    "|", typeof promoCode);
console.log(selectedItem, "|", typeof selectedItem);  // note: typeof null
console.log(templateDemo);
console.log("After tax (₹):", discounted.toFixed(2));

